import { useEffect, useState, useCallback } from "react";
import { useNavigate } from "react-router-dom";
import axios from "axios";
import {
  LogOut,
  Shield,
  Plus,
  Pencil,
  Trash2,
  Mountain,
  MapPin,
  Clock,
  ChevronDown,
  ChevronUp,
  X,
  Upload,
  Image,
  FileText,
  Loader2,
} from "lucide-react";
import { useLogoutHandler } from "../hooks/useLogoutHandler";
import LogoutModal from "../components/LogoutModal";

const API = "http://localhost:5000/api";

/* ──────────────────────────────────────────
   ADMIN DASHBOARD
────────────────────────────────────────── */
const AdminDashboard = () => {
  const navigate = useNavigate();
  const [user, setUser] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const { handleLogout, handleStayLoggedIn, showLogoutModal, setShowLogoutModal } = useLogoutHandler();

  // Trail state
  const [trails, setTrails] = useState([]);
  const [trailsLoading, setTrailsLoading] = useState(false);
  const [expandedTrail, setExpandedTrail] = useState(null);
  const [showCreateForm, setShowCreateForm] = useState(false);
  const [editingTrail, setEditingTrail] = useState(null);

  // Auth check
  useEffect(() => {
    const token = localStorage.getItem("token");
    const userData = localStorage.getItem("user");
    if (token && userData) {
      const parsedUser = JSON.parse(userData);
      if (parsedUser.user_type === "admin") {
        setUser(parsedUser);
        setIsLoading(false);
      } else {
        navigate("/login", { replace: true });
      }
    } else {
      navigate("/login", { replace: true });
    }
  }, [navigate]);

  // Fetch trails
  const fetchTrails = useCallback(async () => {
    setTrailsLoading(true);
    try {
      const token = localStorage.getItem("token");
      const res = await axios.get(`${API}/trails`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setTrails(res.data.trails);
    } catch (err) {
      console.error("Error fetching trails:", err);
    } finally {
      setTrailsLoading(false);
    }
  }, []);

  useEffect(() => {
    if (!isLoading && user) fetchTrails();
  }, [isLoading, user, fetchTrails]);

  // Delete trail
  const handleDeleteTrail = async (trailId) => {
    if (!window.confirm("Are you sure you want to delete this trail? This action cannot be undone.")) return;
    try {
      const token = localStorage.getItem("token");
      await axios.delete(`${API}/trails/${trailId}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setTrails((prev) => prev.filter((t) => t.trail_id !== trailId));
    } catch (err) {
      console.error("Error deleting trail:", err);
      alert("Failed to delete trail");
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-blue-50">
      {/* ── Nav ── */}
      <nav className="bg-white shadow-sm border-b">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-16">
            <div className="flex items-center">
              <Shield className="h-8 w-8 text-blue-600 mr-2" />
              <span className="text-xl font-bold text-gray-900">OffTrailNepal Admin</span>
            </div>
            <button
              onClick={setShowLogoutModal}
              className="flex items-center space-x-2 px-4 py-2 bg-red-600 hover:bg-red-700 text-white rounded-xl font-semibold transition-colors duration-300"
            >
              <LogOut className="h-5 w-5" />
              <span>Logout</span>
            </button>
          </div>
        </div>
      </nav>

      {/* ── Main ── */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Welcome */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-gray-900">Admin Dashboard</h1>
          <p className="text-gray-600 mt-2">Welcome back, {user?.full_name || "Admin"} 🛡️</p>
        </div>

        {/* ── Trail Management Header ── */}
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
            <Mountain className="h-6 w-6 text-blue-600" />
            Trekking Trails
          </h2>
          <button
            onClick={() => {
              setEditingTrail(null);
              setShowCreateForm(!showCreateForm);
            }}
            className="flex items-center gap-2 px-5 py-2.5 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-semibold transition-colors"
          >
            {showCreateForm ? <X className="h-5 w-5" /> : <Plus className="h-5 w-5" />}
            {showCreateForm ? "Cancel" : "Create Trail"}
          </button>
        </div>

        {/* ── Create Trail Form ── */}
        {showCreateForm && (
          <CreateTrailForm
            onSuccess={() => {
              setShowCreateForm(false);
              fetchTrails();
            }}
            onCancel={() => setShowCreateForm(false)}
          />
        )}

        {editingTrail && (
          <EditTrailForm
            trail={editingTrail}
            onSuccess={() => {
              setEditingTrail(null);
              fetchTrails();
            }}
            onCancel={() => setEditingTrail(null)}
          />
        )}

        {/* ── Trail Listing ── */}
        {trailsLoading ? (
          <div className="flex justify-center py-16">
            <Loader2 className="h-8 w-8 animate-spin text-blue-600" />
          </div>
        ) : trails.length === 0 ? (
          <div className="bg-white rounded-2xl shadow-sm border p-12 text-center">
            <Mountain className="h-16 w-16 text-gray-300 mx-auto mb-4" />
            <h3 className="text-xl font-semibold text-gray-700 mb-2">No Trails Yet</h3>
            <p className="text-gray-500">Click "Create Trail" to add your first trekking trail.</p>
          </div>
        ) : (
          <div className="space-y-4">
            {trails.map((trail) => (
              <TrailCard
                key={trail.trail_id}
                trail={trail}
                isExpanded={expandedTrail === trail.trail_id}
                onToggle={() =>
                  setExpandedTrail(expandedTrail === trail.trail_id ? null : trail.trail_id)
                }
                onEdit={() => {
                  setShowCreateForm(false);
                  setEditingTrail(trail);
                }}
                onDelete={() => handleDeleteTrail(trail.trail_id)}
              />
            ))}
          </div>
        )}
      </div>

      <LogoutModal
        isOpen={showLogoutModal}
        onConfirm={handleLogout}
        onCancel={handleStayLoggedIn}
      />
    </div>
  );
};

/* ──────────────────────────────────────────
   TRAIL CARD (listing)
────────────────────────────────────────── */
const TrailCard = ({ trail, isExpanded, onToggle, onEdit, onDelete }) => {
  const primaryImage = trail.images?.find((img) => img.is_primary);
  const difficultyColor = {
    Easy: "bg-green-100 text-green-700",
    Moderate: "bg-yellow-100 text-yellow-700",
    Difficult: "bg-orange-100 text-orange-700",
    Extreme: "bg-red-100 text-red-700",
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border overflow-hidden hover:shadow-md transition-shadow">
      {/* Header */}
      <div className="flex items-center gap-4 p-5 cursor-pointer" onClick={onToggle}>
        {/* Thumbnail */}
        <div className="w-20 h-20 rounded-xl overflow-hidden flex-shrink-0 bg-gray-100">
          {primaryImage ? (
            <img
              src={`http://localhost:5000${primaryImage.image_path}`}
              alt={trail.trail_name}
              className="w-full h-full object-cover"
            />
          ) : (
            <div className="w-full h-full flex items-center justify-center">
              <Mountain className="h-8 w-8 text-gray-300" />
            </div>
          )}
        </div>

        {/* Info */}
        <div className="flex-1 min-w-0">
          <h3 className="text-lg font-bold text-gray-900 truncate">{trail.trail_name}</h3>
          <div className="flex flex-wrap items-center gap-3 mt-1 text-sm text-gray-500">
            <span className="flex items-center gap-1">
              <MapPin className="h-4 w-4" />
              {trail.region}
            </span>
            <span className="flex items-center gap-1">
              <Clock className="h-4 w-4" />
              {trail.duration_days} days
            </span>
            {trail.max_altitude && (
              <span className="flex items-center gap-1">
                <Mountain className="h-4 w-4" />
                {trail.max_altitude}m
              </span>
            )}
            <span
              className={`px-2.5 py-0.5 rounded-full text-xs font-medium ${
                difficultyColor[trail.difficulty_level] || "bg-gray-100 text-gray-700"
              }`}
            >
              {trail.difficulty_level}
            </span>
          </div>
        </div>

        {/* Actions */}
        <div className="flex items-center gap-2 flex-shrink-0">
          <button
            onClick={(e) => {
              e.stopPropagation();
              onEdit();
            }}
            className="p-2 text-blue-500 hover:bg-blue-50 rounded-lg transition"
            title="Edit trail"
          >
            <Pencil className="h-5 w-5" />
          </button>
          <button
            onClick={(e) => {
              e.stopPropagation();
              onDelete();
            }}
            className="p-2 text-red-500 hover:bg-red-50 rounded-lg transition"
            title="Delete trail"
          >
            <Trash2 className="h-5 w-5" />
          </button>
          {isExpanded ? (
            <ChevronUp className="h-5 w-5 text-gray-400" />
          ) : (
            <ChevronDown className="h-5 w-5 text-gray-400" />
          )}
        </div>
      </div>

      {/* Expanded Detail */}
      {isExpanded && (
        <div className="border-t px-5 pb-5">
          {/* Description */}
          <div className="pt-4 pb-3">
            <h4 className="text-sm font-semibold text-gray-700 mb-1">Description</h4>
            <p className="text-gray-600 text-sm leading-relaxed">{trail.description}</p>
          </div>

          {/* Trail Images */}
          {trail.images && trail.images.length > 0 && (
            <div className="pb-4">
              <h4 className="text-sm font-semibold text-gray-700 mb-2">Images</h4>
              <div className="flex gap-3 overflow-x-auto pb-2">
                {trail.images.map((img) => (
                  <div
                    key={img.image_id}
                    className={`w-32 h-24 rounded-lg overflow-hidden flex-shrink-0 border-2 ${
                      img.is_primary ? "border-blue-500" : "border-transparent"
                    }`}
                  >
                    <img
                      src={`http://localhost:5000${img.image_path}`}
                      alt="Trail"
                      className="w-full h-full object-cover"
                    />
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Itinerary */}
          {trail.itineraries && trail.itineraries.length > 0 && (
            <div>
              <h4 className="text-sm font-semibold text-gray-700 mb-2">Itinerary</h4>
              <div className="space-y-2">
                {trail.itineraries.map((it) => (
                  <div
                    key={it.itinerary_id}
                    className="bg-gray-50 rounded-lg p-3 border"
                  >
                    <div className="flex items-center gap-2 mb-1">
                      <span className="bg-blue-600 text-white text-xs font-bold px-2 py-0.5 rounded">
                        Day {it.day_number}
                      </span>
                      {it.title && (
                        <span className="text-sm font-medium text-gray-900">{it.title}</span>
                      )}
                    </div>
                    <p className="text-sm text-gray-600">{it.description}</p>
                    <div className="flex gap-4 mt-1 text-xs text-gray-400">
                      {it.altitude && <span>Alt: {it.altitude}m</span>}
                      {it.distance_km && <span>Dist: {it.distance_km} km</span>}
                      {it.walking_hours && <span>Walk: {it.walking_hours} hrs</span>}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* GPX */}
          {trail.gpx_file_path && (
            <div className="mt-3">
              <a
                href={`http://localhost:5000${trail.gpx_file_path}`}
                target="_blank"
                rel="noopener noreferrer"
                className="inline-flex items-center gap-1 text-sm text-blue-600 hover:underline"
              >
                <FileText className="h-4 w-4" />
                Download GPX File
              </a>
            </div>
          )}

          {/* Meta */}
          <div className="mt-3 text-xs text-gray-400">
            Approved by: {trail.approved_by_name || "Admin"} &middot; Created:{" "}
            {new Date(trail.created_at).toLocaleDateString()}
          </div>
        </div>
      )}
    </div>
  );
};

/* ──────────────────────────────────────────
   CREATE TRAIL FORM
────────────────────────────────────────── */
const EMPTY_ITINERARY = {
  day_number: 1,
  title: "",
  description: "",
  altitude: "",
  distance_km: "",
  walking_hours: "",
};

const MAX_TRAIL_IMAGES = 3;

const CreateTrailForm = ({ onSuccess, onCancel }) => {
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");

  // Trail fields
  const [trailName, setTrailName] = useState("");
  const [difficulty, setDifficulty] = useState("Moderate");
  const [durationDays, setDurationDays] = useState("");
  const [maxAltitude, setMaxAltitude] = useState("");
  const [description, setDescription] = useState("");
  const [region, setRegion] = useState("");

  // Files
  const [gpxFile, setGpxFile] = useState(null);
  const [images, setImages] = useState([]);
  const [imagePreviews, setImagePreviews] = useState([]);

  // Itineraries
  const [itineraries, setItineraries] = useState([{ ...EMPTY_ITINERARY }]);

  const handleImageChange = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (images.length >= MAX_TRAIL_IMAGES) {
      setError(`You can upload up to ${MAX_TRAIL_IMAGES} images only.`);
      e.target.value = "";
      return;
    }

    setImages((prev) => [...prev, file]);
    setImagePreviews((prev) => [...prev, URL.createObjectURL(file)]);
    e.target.value = "";
  };

  const removeSelectedImage = (index) => {
    setImages((prev) => prev.filter((_, idx) => idx !== index));
    setImagePreviews((prev) => prev.filter((_, idx) => idx !== index));
  };

  const addItinerary = () => {
    setItineraries((prev) => [
      ...prev,
      { ...EMPTY_ITINERARY, day_number: prev.length + 1 },
    ]);
  };

  const removeItinerary = (index) => {
    setItineraries((prev) => {
      const updated = prev.filter((_, i) => i !== index);
      return updated.map((it, i) => ({ ...it, day_number: i + 1 }));
    });
  };

  const updateItinerary = (index, field, value) => {
    setItineraries((prev) =>
      prev.map((it, i) => (i === index ? { ...it, [field]: value } : it))
    );
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");

    if (!trailName || !difficulty || !durationDays || !description || !region) {
      setError("Please fill in all required trail fields.");
      return;
    }

    // Validate itineraries descriptions
    for (const it of itineraries) {
      if (!it.description.trim()) {
        setError(`Day ${it.day_number} is missing a description.`);
        return;
      }
    }

    setSubmitting(true);

    try {
      const token = localStorage.getItem("token");
      const formData = new FormData();
      formData.append("trail_name", trailName);
      formData.append("difficulty_level", difficulty);
      formData.append("duration_days", durationDays);
      formData.append("max_altitude", maxAltitude);
      formData.append("description", description);
      formData.append("region", region);
      formData.append("itineraries", JSON.stringify(itineraries));

      if (gpxFile) formData.append("gpx_file", gpxFile);
      for (const img of images) {
        formData.append("images", img);
      }

      await axios.post(`${API}/trails`, formData, {
        headers: {
          Authorization: `Bearer ${token}`,
          "Content-Type": "multipart/form-data",
        },
      });

      onSuccess();
    } catch (err) {
      console.error(err);
      setError(err.response?.data?.message || "Failed to create trail.");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <form
      onSubmit={handleSubmit}
      className="bg-white rounded-2xl shadow-sm border p-6 mb-6"
    >
      <h3 className="text-xl font-bold text-gray-900 mb-5 flex items-center gap-2">
        <Plus className="h-5 w-5 text-blue-600" />
        Create New Trail
      </h3>

      {error && (
        <div className="mb-4 p-3 bg-red-50 border border-red-200 rounded-xl text-red-700 text-sm">
          {error}
        </div>
      )}

      {/* ── Trail Basic Info ── */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">
            Trail Name <span className="text-red-500">*</span>
          </label>
          <input
            type="text"
            value={trailName}
            onChange={(e) => setTrailName(e.target.value)}
            className="w-full px-4 py-2.5 border rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
            placeholder="e.g. Kori Himal Trek"
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">
            Region <span className="text-red-500">*</span>
          </label>
          <input
            type="text"
            value={region}
            onChange={(e) => setRegion(e.target.value)}
            className="w-full px-4 py-2.5 border rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
            placeholder="e.g. Solukhumbu"
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">
            Difficulty Level <span className="text-red-500">*</span>
          </label>
          <select
            value={difficulty}
            onChange={(e) => setDifficulty(e.target.value)}
            className="w-full px-4 py-2.5 border rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none bg-white"
          >
            <option value="Easy">Easy</option>
            <option value="Moderate">Moderate</option>
            <option value="Difficult">Difficult</option>
            <option value="Extreme">Extreme</option>
          </select>
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">
            Duration (days) <span className="text-red-500">*</span>
          </label>
          <input
            type="number"
            value={durationDays}
            onChange={(e) => setDurationDays(e.target.value)}
            className="w-full px-4 py-2.5 border rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
            min="1"
            placeholder="e.g. 12"
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">
            Max Altitude (m)
          </label>
          <input
            type="number"
            value={maxAltitude}
            onChange={(e) => setMaxAltitude(e.target.value)}
            className="w-full px-4 py-2.5 border rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
            placeholder="e.g. 5364"
          />
        </div>
      </div>

      <div className="mb-6">
        <label className="block text-sm font-medium text-gray-700 mb-1">
          Description <span className="text-red-500">*</span>
        </label>
        <textarea
          value={description}
          onChange={(e) => setDescription(e.target.value)}
          rows={4}
          className="w-full px-4 py-2.5 border rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none resize-none"
          placeholder="Describe the trail, highlights, best season, etc."
        />
      </div>

      {/* ── File Uploads ── */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
        {/* GPX */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">
            GPX File
          </label>
          <label className="flex items-center gap-2 px-4 py-2.5 border-2 border-dashed rounded-xl cursor-pointer hover:border-blue-400 transition">
            <Upload className="h-5 w-5 text-gray-400" />
            <span className="text-sm text-gray-500">
              {gpxFile ? gpxFile.name : "Choose .gpx file"}
            </span>
            <input
              type="file"
              accept=".gpx"
              className="hidden"
              onChange={(e) => setGpxFile(e.target.files[0] || null)}
            />
          </label>
        </div>

        {/* Images */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">
            Trail Images (upload one by one, max 3)
          </label>
          <label className="flex items-center gap-2 px-4 py-2.5 border-2 border-dashed rounded-xl cursor-pointer hover:border-blue-400 transition">
            <Image className="h-5 w-5 text-gray-400" />
            <span className="text-sm text-gray-500">
              {images.length > 0
                ? `${images.length}/${MAX_TRAIL_IMAGES} image(s) selected`
                : "Click to add 1 image"}
            </span>
            <input
              type="file"
              accept="image/jpeg,image/png,image/webp"
              className="hidden"
              disabled={images.length >= MAX_TRAIL_IMAGES}
              onChange={handleImageChange}
            />
          </label>
          <p className="text-xs text-gray-400 mt-1">
            First uploaded image will be used as primary thumbnail.
          </p>
        </div>
      </div>

      {/* Image Previews */}
      {imagePreviews.length > 0 && (
        <div className="flex gap-3 overflow-x-auto pb-2 mb-6">
          {imagePreviews.map((src, i) => (
            <div
              key={i}
              className={`w-24 h-20 rounded-lg overflow-hidden flex-shrink-0 border-2 ${
                i === 0 ? "border-blue-500" : "border-gray-200"
              }`}
            >
              <img src={src} alt={`Preview ${i + 1}`} className="w-full h-full object-cover" />
              <button
                type="button"
                onClick={() => removeSelectedImage(i)}
                className="absolute mt-1 ml-1 bg-white/90 rounded-full p-1 text-red-500"
                title="Remove image"
              >
                <X className="h-3 w-3" />
              </button>
            </div>
          ))}
        </div>
      )}

      {/* ── Itinerary ── */}
      <div className="mb-6">
        <div className="flex items-center justify-between mb-3">
          <h4 className="text-sm font-semibold text-gray-700">Day-by-Day Itinerary</h4>
          <button
            type="button"
            onClick={addItinerary}
            className="text-sm text-blue-600 hover:text-blue-700 font-medium flex items-center gap-1"
          >
            <Plus className="h-4 w-4" /> Add Day
          </button>
        </div>

        <div className="space-y-3">
          {itineraries.map((it, idx) => (
            <div key={idx} className="bg-gray-50 border rounded-xl p-4">
              <div className="flex items-center justify-between mb-2">
                <span className="bg-blue-600 text-white text-xs font-bold px-2 py-0.5 rounded">
                  Day {it.day_number}
                </span>
                {itineraries.length > 1 && (
                  <button
                    type="button"
                    onClick={() => removeItinerary(idx)}
                    className="text-red-400 hover:text-red-600"
                  >
                    <Trash2 className="h-4 w-4" />
                  </button>
                )}
              </div>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-3 mb-2">
                <input
                  type="text"
                  value={it.title}
                  onChange={(e) => updateItinerary(idx, "title", e.target.value)}
                  className="col-span-1 md:col-span-3 px-3 py-2 border rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                  placeholder="Title (e.g. Pokhara to Tikhedhunga)"
                />
                <input
                  type="number"
                  value={it.altitude}
                  onChange={(e) => updateItinerary(idx, "altitude", e.target.value)}
                  className="px-3 py-2 border rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                  placeholder="Altitude (m)"
                />
                <input
                  type="number"
                  step="0.01"
                  value={it.distance_km}
                  onChange={(e) => updateItinerary(idx, "distance_km", e.target.value)}
                  className="px-3 py-2 border rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                  placeholder="Distance (km)"
                />
                <input
                  type="number"
                  step="0.5"
                  value={it.walking_hours}
                  onChange={(e) => updateItinerary(idx, "walking_hours", e.target.value)}
                  className="px-3 py-2 border rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                  placeholder="Walking hours"
                />
              </div>
              <textarea
                value={it.description}
                onChange={(e) => updateItinerary(idx, "description", e.target.value)}
                rows={2}
                className="w-full px-3 py-2 border rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none resize-none"
                placeholder="Day description *"
              />
            </div>
          ))}
        </div>
      </div>

      {/* ── Actions ── */}
      <div className="flex justify-end gap-3">
        <button
          type="button"
          onClick={onCancel}
          className="px-5 py-2.5 border rounded-xl text-gray-700 hover:bg-gray-50 font-medium transition"
        >
          Cancel
        </button>
        <button
          type="submit"
          disabled={submitting}
          className="px-6 py-2.5 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-semibold transition-colors flex items-center gap-2 disabled:opacity-60"
        >
          {submitting ? (
            <>
              <Loader2 className="h-5 w-5 animate-spin" />
              Creating...
            </>
          ) : (
            <>
              <Plus className="h-5 w-5" />
              Create Trail
            </>
          )}
        </button>
      </div>
    </form>
  );
};

const EditTrailForm = ({ trail, onSuccess, onCancel }) => {
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");

  const [trailName, setTrailName] = useState(trail.trail_name || "");
  const [difficulty, setDifficulty] = useState(trail.difficulty_level || "Moderate");
  const [durationDays, setDurationDays] = useState(trail.duration_days || "");
  const [maxAltitude, setMaxAltitude] = useState(trail.max_altitude || "");
  const [description, setDescription] = useState(trail.description || "");
  const [region, setRegion] = useState(trail.region || "");

  const [gpxFile, setGpxFile] = useState(null);
  const [images, setImages] = useState([]);
  const [imagePreviews, setImagePreviews] = useState([]);

  const [itineraries, setItineraries] = useState(
    trail.itineraries && trail.itineraries.length > 0
      ? trail.itineraries.map((it, index) => ({
          day_number: index + 1,
          title: it.title || "",
          description: it.description || "",
          altitude: it.altitude || "",
          distance_km: it.distance_km || "",
          walking_hours: it.walking_hours || "",
        }))
      : [{ ...EMPTY_ITINERARY }]
  );

  const handleImageChange = (e) => {
    const files = Array.from(e.target.files);
    setImages(files);
    setImagePreviews(files.map((f) => URL.createObjectURL(f)));
  };

  const addItinerary = () => {
    setItineraries((prev) => [
      ...prev,
      { ...EMPTY_ITINERARY, day_number: prev.length + 1 },
    ]);
  };

  const removeItinerary = (index) => {
    setItineraries((prev) => {
      const updated = prev.filter((_, i) => i !== index);
      return updated.map((it, i) => ({ ...it, day_number: i + 1 }));
    });
  };

  const updateItinerary = (index, field, value) => {
    setItineraries((prev) =>
      prev.map((it, i) => (i === index ? { ...it, [field]: value } : it))
    );
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");

    if (!trailName || !difficulty || !durationDays || !description || !region) {
      setError("Please fill in all required trail fields.");
      return;
    }

    for (const it of itineraries) {
      if (!it.description.trim()) {
        setError(`Day ${it.day_number} is missing a description.`);
        return;
      }
    }

    setSubmitting(true);

    try {
      const token = localStorage.getItem("token");
      const formData = new FormData();
      formData.append("trail_name", trailName);
      formData.append("difficulty_level", difficulty);
      formData.append("duration_days", durationDays);
      formData.append("max_altitude", maxAltitude);
      formData.append("description", description);
      formData.append("region", region);
      formData.append("itineraries", JSON.stringify(itineraries));

      if (gpxFile) formData.append("gpx_file", gpxFile);
      for (const img of images) {
        formData.append("images", img);
      }

      await axios.put(`${API}/trails/${trail.trail_id}`, formData, {
        headers: {
          Authorization: `Bearer ${token}`,
          "Content-Type": "multipart/form-data",
        },
      });

      onSuccess();
    } catch (err) {
      console.error(err);
      setError(err.response?.data?.message || "Failed to update trail.");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <form
      onSubmit={handleSubmit}
      className="bg-white rounded-2xl shadow-sm border p-6 mb-6"
    >
      <h3 className="text-xl font-bold text-gray-900 mb-5 flex items-center gap-2">
        <Pencil className="h-5 w-5 text-blue-600" />
        Edit Trail
      </h3>

      {error && (
        <div className="mb-4 p-3 bg-red-50 border border-red-200 rounded-xl text-red-700 text-sm">
          {error}
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">
            Trail Name <span className="text-red-500">*</span>
          </label>
          <input
            type="text"
            value={trailName}
            onChange={(e) => setTrailName(e.target.value)}
            className="w-full px-4 py-2.5 border rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">
            Region <span className="text-red-500">*</span>
          </label>
          <input
            type="text"
            value={region}
            onChange={(e) => setRegion(e.target.value)}
            className="w-full px-4 py-2.5 border rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">
            Difficulty Level <span className="text-red-500">*</span>
          </label>
          <select
            value={difficulty}
            onChange={(e) => setDifficulty(e.target.value)}
            className="w-full px-4 py-2.5 border rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none bg-white"
          >
            <option value="Easy">Easy</option>
            <option value="Moderate">Moderate</option>
            <option value="Difficult">Difficult</option>
            <option value="Extreme">Extreme</option>
          </select>
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">
            Duration (days) <span className="text-red-500">*</span>
          </label>
          <input
            type="number"
            value={durationDays}
            onChange={(e) => setDurationDays(e.target.value)}
            className="w-full px-4 py-2.5 border rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
            min="1"
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">
            Max Altitude (m)
          </label>
          <input
            type="number"
            value={maxAltitude}
            onChange={(e) => setMaxAltitude(e.target.value)}
            className="w-full px-4 py-2.5 border rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
          />
        </div>
      </div>

      <div className="mb-6">
        <label className="block text-sm font-medium text-gray-700 mb-1">
          Description <span className="text-red-500">*</span>
        </label>
        <textarea
          value={description}
          onChange={(e) => setDescription(e.target.value)}
          rows={4}
          className="w-full px-4 py-2.5 border rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none resize-none"
        />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-3">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Replace GPX File</label>
          <label className="flex items-center gap-2 px-4 py-2.5 border-2 border-dashed rounded-xl cursor-pointer hover:border-blue-400 transition">
            <Upload className="h-5 w-5 text-gray-400" />
            <span className="text-sm text-gray-500">{gpxFile ? gpxFile.name : "Choose .gpx file"}</span>
            <input
              type="file"
              accept=".gpx"
              className="hidden"
              onChange={(e) => setGpxFile(e.target.files[0] || null)}
            />
          </label>
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Add More Images</label>
          <label className="flex items-center gap-2 px-4 py-2.5 border-2 border-dashed rounded-xl cursor-pointer hover:border-blue-400 transition">
            <Image className="h-5 w-5 text-gray-400" />
            <span className="text-sm text-gray-500">
              {images.length > 0 ? `${images.length} file(s) selected` : "Choose images"}
            </span>
            <input
              type="file"
              accept="image/jpeg,image/png,image/webp"
              multiple
              className="hidden"
              onChange={handleImageChange}
            />
          </label>
        </div>
      </div>

      {imagePreviews.length > 0 && (
        <div className="flex gap-3 overflow-x-auto pb-2 mb-6">
          {imagePreviews.map((src, i) => (
            <div key={i} className="w-24 h-20 rounded-lg overflow-hidden flex-shrink-0 border-2 border-gray-200">
              <img src={src} alt={`Preview ${i + 1}`} className="w-full h-full object-cover" />
            </div>
          ))}
        </div>
      )}

      <div className="mb-6">
        <div className="flex items-center justify-between mb-3">
          <h4 className="text-sm font-semibold text-gray-700">Day-by-Day Itinerary</h4>
          <button
            type="button"
            onClick={addItinerary}
            className="text-sm text-blue-600 hover:text-blue-700 font-medium flex items-center gap-1"
          >
            <Plus className="h-4 w-4" /> Add Day
          </button>
        </div>

        <div className="space-y-3">
          {itineraries.map((it, idx) => (
            <div key={idx} className="bg-gray-50 border rounded-xl p-4">
              <div className="flex items-center justify-between mb-2">
                <span className="bg-blue-600 text-white text-xs font-bold px-2 py-0.5 rounded">
                  Day {it.day_number}
                </span>
                {itineraries.length > 1 && (
                  <button
                    type="button"
                    onClick={() => removeItinerary(idx)}
                    className="text-red-400 hover:text-red-600"
                  >
                    <Trash2 className="h-4 w-4" />
                  </button>
                )}
              </div>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-3 mb-2">
                <input
                  type="text"
                  value={it.title}
                  onChange={(e) => updateItinerary(idx, "title", e.target.value)}
                  className="col-span-1 md:col-span-3 px-3 py-2 border rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                  placeholder="Title"
                />
                <input
                  type="number"
                  value={it.altitude}
                  onChange={(e) => updateItinerary(idx, "altitude", e.target.value)}
                  className="px-3 py-2 border rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                  placeholder="Altitude (m)"
                />
                <input
                  type="number"
                  step="0.01"
                  value={it.distance_km}
                  onChange={(e) => updateItinerary(idx, "distance_km", e.target.value)}
                  className="px-3 py-2 border rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                  placeholder="Distance (km)"
                />
                <input
                  type="number"
                  step="0.5"
                  value={it.walking_hours}
                  onChange={(e) => updateItinerary(idx, "walking_hours", e.target.value)}
                  className="px-3 py-2 border rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                  placeholder="Walking hours"
                />
              </div>
              <textarea
                value={it.description}
                onChange={(e) => updateItinerary(idx, "description", e.target.value)}
                rows={2}
                className="w-full px-3 py-2 border rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none resize-none"
                placeholder="Day description *"
              />
            </div>
          ))}
        </div>
      </div>

      <div className="flex justify-end gap-3">
        <button
          type="button"
          onClick={onCancel}
          className="px-5 py-2.5 border rounded-xl text-gray-700 hover:bg-gray-50 font-medium transition"
        >
          Cancel
        </button>
        <button
          type="submit"
          disabled={submitting}
          className="px-6 py-2.5 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-semibold transition-colors flex items-center gap-2 disabled:opacity-60"
        >
          {submitting ? (
            <>
              <Loader2 className="h-5 w-5 animate-spin" />
              Updating...
            </>
          ) : (
            <>
              <Pencil className="h-5 w-5" />
              Update Trail
            </>
          )}
        </button>
      </div>
    </form>
  );
};

export default AdminDashboard;
